+  const versionMatch = normalized.match(/\bclaude-[a-z0-9-]*?-(\d+)(?:-(\d+))?(?:\b|[-])/i);
+  if (!versionMatch) {
+    return false;
+  }
+  const major = Number.parseInt(versionMatch[1] ?? "0", 10);
+  const minor = Number.parseInt(versionMatch[2] ?? "0", 10);
+  if (major > 4) {
+    return true;
+  }
+  if (major < 4) {
+    return false;
+  }
+  return minor >= 6;
 }

